import React, { createContext, useContext, useState, useEffect } from 'react';

const CartContext = createContext();
export const useCart = () => useContext(CartContext);

export const CartProvider = ({ children }) => {
  const [items, setItems] = useState(() => {
    try {
      const saved = localStorage.getItem('lib_cart');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  useEffect(() => {
    localStorage.setItem('lib_cart', JSON.stringify(items));
  }, [items]);

  const addToCart = (book) => {
    setItems(prev => {
      const exists = prev.find(i => i._id === book._id);
      if (exists) return prev; // already in cart
      return [...prev, { ...book, addedAt: new Date().toISOString() }];
    });
  };

  const removeFromCart = (bookId) => {
    setItems(prev => prev.filter(i => i._id !== bookId));
  };

  const isInCart = (bookId) => items.some(i => i._id === bookId);

  const clearCart = () => setItems([]);

  return (
    <CartContext.Provider value={{ items, addToCart, removeFromCart, isInCart, clearCart, count: items.length }}>
      {children}
    </CartContext.Provider>
  );
};
